// // (1) reset: Resets the counter to 5'b11111.
// (2) load: Loads a specified value into the counter when low.
// (3) data: 5-bit value to be loaded when load is low.
// (4) q: The value of the counter.
module top_module(
    input clk,
    input reset,
    input load,
    input [4:0] data,
    output reg [4:0] q
);

    always @(posedge clk) begin
        if (reset) begin
            // Synchronous reset: Reset the counter to 5'b00000
            q <= 5'b00000;
        end else if (load) begin
            // Load the specified value into the counter
            q <= data;
        end else begin
            // Increment the counter
            q <= q + 1;
        end
    end

endmodule

